import{_ as e,o as i,c as o,a0 as n}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"Introduction to SwiftList","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),s={name:"guide/introduction.md"};function a(r,t,l,d,c,p){return i(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="introduction-to-swiftlist" tabindex="-1">Introduction to SwiftList <a class="header-anchor" href="#introduction-to-swiftlist" aria-label="Permalink to &quot;Introduction to SwiftList&quot;">​</a></h1><p>SwiftList is a high-performance, low-overhead, and highly extensible global search utility designed for Windows, aiming to be a beautiful, deeply customizable, open-source alternative to <strong>Listary</strong>. It quickly builds and maintains indexes for local files, while offering a plugin SDK for developers to extend its capabilities.</p><h2 id="download-installation" tabindex="-1">Download &amp; Installation <a class="header-anchor" href="#download-installation" aria-label="Permalink to &quot;Download &amp; Installation&quot;">​</a></h2><p>SwiftList provides official installer and portable zip releases (Latest Stable Version):</p><ul><li>💾 <strong><a href="https://github.com/SwiftList/SwiftList/releases/latest/download/SwiftList-Setup.exe" target="_blank" rel="noreferrer">Download Installer</a></strong> — Full installer package (supports auto-start and background Windows Service indexing).</li><li>📦 <strong><a href="https://github.com/SwiftList/SwiftList/releases/latest/download/SwiftList-Portable.zip" target="_blank" rel="noreferrer">Download Portable Version</a></strong> — Standalone portable version.</li><li>🔍 Or visit <strong><a href="https://github.com/SwiftList/SwiftList/releases" target="_blank" rel="noreferrer">GitHub Releases Page</a></strong> to check all historical versions.</li></ul><h2 id="core-design-principles" tabindex="-1">Core Design Principles <a class="header-anchor" href="#core-design-principles" aria-label="Permalink to &quot;Core Design Principles&quot;">​</a></h2><ol><li><strong>YAGNI (You Aren&#39;t Gonna Need It)</strong>: Refuse bloated design; keep logic concise and execution fast.</li><li><strong>Process Separation &amp; Isolation</strong>: <ul><li><strong><code>SwiftList.Service</code> (System Service - <code>--service</code>)</strong>: Runs in Session 0 with SYSTEM privileges, indexing NTFS MFT and USN logs, shared globally.</li><li><strong><code>SwiftList.Service</code> (Hook Process - <code>--hook</code>)</strong>: Runs in the user session, capturing global keyboard hotkeys and tracking explorer paths.</li><li><strong><code>SwiftList.App</code> (User Application)</strong>: Runs in the user session, hosting UI interactions, rendering search results, and loading user-scoped plugins.</li></ul></li><li><strong>High-Speed FZF Matching</strong>: Optimized search matching supporting fuzzy queries, Pinyin initials, and customized aliases.</li></ol><h2 id="🎁-donation-support" tabindex="-1">🎁 Donation &amp; Support <a class="header-anchor" href="#🎁-donation-support" aria-label="Permalink to &quot;🎁 Donation &amp; Support&quot;">​</a></h2><p>If you find SwiftList helpful, thank you very much for your support and sponsorship!</p><ul><li><strong>Tether USDT (TRC20)</strong> Address: <code>TNDh3husX1trDW2ZPm4ZZYdoCoCRCZQXn5</code></li></ul>',10)])])}const h=e(s,[["render",a]]);export{g as __pageData,h as default};
